import{_ as a}from"./header-DMnyEjis.js";import{_ as r,a as t,b as o}from"./tougleMeasure-gPsfTp5t.js";import{_ as i,c as s,a as n,o as m}from"./app-Cmngj56S.js";const p="/assets/menubar-D_HHk24r.png",l="/assets/upload_mei-Pzt9Qjln.png",d="/assets/importIIIf-CCo2kQBr.png",h={};function g(c,e){return m(),s("div",null,e[0]||(e[0]=[n('<h1 id="header" tabindex="-1"><a class="header-anchor" href="#header"><span>Header</span></a></h1><p>In the Cartographer App, the header contains a title (see number 1 in Image 2) and a dropdown menu button (see number 2 in Image 2).</p><p>Clicking the menu reveals buttons for uploading or downloading MEI files, and for loading IIIF image files from a server.<br> Additionally, the header includes buttons to show the <strong>Page Overview</strong> and to toggle the <strong>Measure List</strong>.</p><p><img src="'+a+'" alt="Cartographer App Header"><br><em>Image 2: Layout of the Cartographer App header</em></p><hr><h2 id="menu-bar" tabindex="-1"><a class="header-anchor" href="#menu-bar"><span>Menu Bar</span></a></h2><p>Clicking the dropdown menu in the header opens five options (see Image 3):</p><p><img src="'+p+'" alt="Header Menu Bar"><br><em>Image 3: Header Menu Bar</em></p><h3 id="upload-mei-file" tabindex="-1"><a class="header-anchor" href="#upload-mei-file"><span>Upload MEI File</span></a></h3><p>Opens a file dialog where you can select and upload a local MEI file.</p><p><img src="'+l+'" alt="Upload MEI File"><br><em>Image 4: Upload MEI file</em></p><h3 id="import-iiif-manifest" tabindex="-1"><a class="header-anchor" href="#import-iiif-manifest"><span>Import IIIF Manifest</span></a></h3><p>Opens a dialog to enter the URL of a IIIF manifest to load image data from a server.</p><p><img src="'+d+'" alt="Import IIIF Manifest"><br><em>Image 5: Import IIIF manifest</em></p><h3 id="download-mei-file" tabindex="-1"><a class="header-anchor" href="#download-mei-file"><span>Download MEI File</span></a></h3><p>Saves the current MEI file to your local machine.</p><h3 id="show-page-overview" tabindex="-1"><a class="header-anchor" href="#show-page-overview"><span>Show Page Overview</span></a></h3><p>Displays a list of all pages with detailed information from an imported file (see figure 6).<br> It also contains a button to copy and paste a IIIF manifest (<em>Import Images button</em>, figure 7).</p><p><img src="'+r+'" alt="Page Overview"><br><em>Image 6: Display list of images</em></p><p><img src="'+t+'" alt="Import Images"><br><em>Image 7: Import Images</em></p><h3 id="toggle-measure-list" tabindex="-1"><a class="header-anchor" href="#toggle-measure-list"><span>Toggle Measure List</span></a></h3><p>Shows or hides the list of musical measures of the document next to the right toolbar.</p><p><img src="'+o+'" alt="Toggle Measures"><br><em>Image 8: Toggle Measures</em></p>',23)]))}const b=i(h,[["render",g]]),_=JSON.parse('{"path":"/user/header.html","title":"Header","lang":"en-US","frontmatter":{},"git":{"updatedTime":1756211745000,"contributors":[{"name":"Hizkiel","username":"Hizkiel","email":"hizclick@gmail.com","commits":1,"url":"https://github.com/Hizkiel"}],"changelog":[{"hash":"f154f171982bcbf31ca935ebf59603fd9f7ba544","time":1756211745000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Remove user documentation directory"}]},"filePathRelative":"user/header.md"}');export{b as comp,_ as data};
